1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G premium for an empty item list (processing fee only)", () => {
7	      const scenario = {
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      };
11	      const result = processScenario(scenario);
12	      expect(result.results[0]).toEqual({ premium: 5 });
13	    });
14	    it.todo("returns 105 G premium for a single sword (100 base + 5 fee)");
15	    it.todo("returns 65 G premium for a single amulet (60 base + 5 fee)");
16	    it.todo("returns 85 G premium for a single staff (80 base + 5 fee)");
17	    it.todo("returns 45 G premium for a single potion (40 base + 5 fee)");
18	    it.todo("returns 30 G premium for a single rune component (25 base + 5 fee)");
19	    it.todo("returns 165 G premium for a sword and an amulet (100 + 60 + 5 fee)");
20	  });
21	
22	  describe("Quote - component block pricing", () => {
23	    it.todo("returns 55 G for 2 runes (2 * 25 = 50 + 5 fee)");
24	    it.todo("returns 65 G for 3 runes (block price 60 + 5 fee)");
25	    it.todo("returns 105 G for 4 runes (4 * 25 = 100 + 5 fee, no block)");
26	    it.todo("returns 80 G for 2 runes and 1 moonstone (no block, different types, 75 + 5 fee)");
27	    it.todo("returns 125 G for 3 runes and 3 moonstones (two blocks, 60 + 60 + 5 fee)");
28	  });
29	
30	  describe("Quote - item-specific modifiers", () => {
31	    it.todo("adds 50% curse surcharge to a cursed sword (100 + 50 + 5 = 155 G)");
32	    it.todo("adds 30% high-enchantment surcharge for enchantment level 5 (100 + 30 + 5 = 135 G)");
33	    it.todo("applies both curse and high-enchantment surcharges (100 + 50 + 30 + 5 = 185 G)");
34	    it.todo("does not apply high-enchantment surcharge for enchantment level 4");
35	    it.todo("applies item-specific modifiers only to the affected item in a multi-item policy");
36	  });
37	
38	  describe("Quote - policy-wide modifiers", () => {
39	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
40	    it.todo("applies 10% first insurance surcharge (always applies per quote)");
41	    it.todo("applies 15% follow-up discount on each contract after the first");
42	    it.todo("applies loyalty discount to customer with exactly 2 years");
43	  });
44	
45	  describe("Quote - integration", () => {
46	    it.todo("newcomer with cursed sword: 0 years, first contract = 165 G");
47	    it.todo("long-standing customer second contract with cursed high-enchantment sword = 160 G");
48	    it.todo("rounds premium up in MHPCO's favor");
49	  });
50	
51	  describe("Claim - basic payout", () => {
52	    it.todo("applies 100 G deductible to damage on a regular sword");
53	    it.todo("returns remaining cap after a claim");
54	    it.todo("fully reimburses dragon-material item minus deductible");
55	    it.todo("reimburses at 50% for enchantment >= 8, then applies deductible");
56	    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
57	  });
58	
59	  describe("Claim - cap and multiple damages", () => {
60	    it.todo("caps total payout at twice the insurance sum");
61	    it.todo("applies deductible per damaged item in a single event");
62	    it.todo("tracks remaining cap across successive claims");
63	    it.todo("reduces payout to remaining cap when cap is nearly exhausted");
64	  });
65	
66	  describe("Claim - payout rounding", () => {
67	    it.todo("rounds payout down in MHPCO's favor");
68	  });
69	
70	  describe("Error handling", () => {
71	    it.todo("rejects unknown item type in a quote");
72	    it.todo("rejects claim damage for item not in policy");
73	    it.todo("rejects negative damage amount");
74	    it.todo("rejects more damages of a type than policy covers");
75	  });
76	
77	  describe("CLI integration", () => {
78	    it.todo("reads scenario from stdin and writes results to stdout");
79	    it.todo("processes sequential quote and claim steps");
80	  });
81	});
82

